#include <stdio.h>
#include <string.h>
#define MOD 1000000007
int dp[51][51][1001];
int hash(int A, int E, int V) {
    if (A == 0 && E == 0) return V == 0;
    if (V < A) return 0;
    if (dp[A][E][V] != -1) return dp[A][E][V];
    int res = 0;
    for (int i = 0; i <= E; i++) {
        int j = E - i;
        res += hash(A, i, V - A) * hash(0, j, 0);
        res %= MOD;
    }
    dp[A][E][V] = res;
    return res;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int A, E, V;
        scanf("%d %d %d", &A, &E, &V);
        memset(dp, -1, sizeof(dp));
        printf("%d\n", hash(A, E, V));
    }
    return 0;
}

