import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    static int[][][] dp = new int[51][51][1001];
    public static int hash(int A, int E, int V) {
        if (A == 0 && E == 0) return V == 0 ? 1 : 0;
        if (V < A) return 0;
        if (dp[A][E][V] != -1) return dp[A][E][V];
        int res = 0;
        for (int i = 0; i <= E; i++) {
            int j = E - i;
            res += hash(A, i, V - A) * hash(0, j, 0);
            res %= MOD;
        }
        dp[A][E][V] = res;
        return res;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int A = sc.nextInt();
            int E = sc.nextInt();
            int V = sc.nextInt();
            for (int i = 0; i < 51; i++) {
                for (int j = 0; j < 51; j++) {
                    for (int k = 0; k < 1001; k++) {
                        dp[i][j][k] = -1;
                    }
                }
            }
            System.out.println(hash(A, E, V));
        }
    }
}

